// TradingServiceServer is the server API for TradingService service.
// All implementations should embed UnimplementedTradingServiceServer
// for forward compatibility.
//
// TradingService owns celina 3-5: actuary management, exchange &
// security catalogs, listings, orders + executions, portfolio, OTC
// (c4), capital-gains tax, investment funds (c4), inter-bank trade
// (c5), and the SAGA orchestrator.
//
// Every RPC with a google.api.http annotation is exposed via the
// gateway at /api/v1/trading/...; unannotated RPCs are reachable only
// inside the cluster (background workers, bank → trading callbacks,
// etc.).
type TradingServiceServer interface {
	GetActuaryInfo(context.Context, *GetActuaryInfoRequest) (*ActuaryInfo, error)
	ListActuaries(context.Context, *ListActuariesRequest) (*ListActuariesResponse, error)
	UpsertActuaryInfo(context.Context, *UpsertActuaryInfoRequest) (*ActuaryInfo, error)
	UpdateActuaryLimit(context.Context, *UpdateActuaryLimitRequest) (*ActuaryInfo, error)
	ResetActuaryUsedLimit(context.Context, *ResetActuaryUsedLimitRequest) (*ActuaryInfo, error)
	SetActuaryNeedApproval(context.Context, *SetActuaryNeedApprovalRequest) (*ActuaryInfo, error)
	// RunDailyResetActuaries is exposed for manual triggers; the same
	// codepath runs nightly at 23:59 (Belgrade) via the trading cron.
	RunDailyResetActuaries(context.Context, *emptypb.Empty) (*RunDailyResetActuariesResponse, error)
	ListExchanges(context.Context, *ListExchangesRequest) (*ListExchangesResponse, error)
	UpsertExchange(context.Context, *UpsertExchangeRequest) (*Exchange, error)
	SetExchangeOverride(context.Context, *SetExchangeOverrideRequest) (*Exchange, error)
	UpsertSecurity(context.Context, *UpsertSecurityRequest) (*Security, error)
	ListSecurities(context.Context, *ListSecuritiesRequest) (*ListSecuritiesResponse, error)
	GetSecurity(context.Context, *GetSecurityRequest) (*SecurityWithListing, error)
	UpsertListing(context.Context, *UpsertListingRequest) (*Listing, error)
	ListListings(context.Context, *ListListingsRequest) (*ListListingsResponse, error)
	GetListing(context.Context, *GetListingRequest) (*Listing, error)
	// GetOptionChain returns the option chain for a stock — call/put
	// pairs grouped by strike, filtered to the N rows nearest the
	// shared (current) price per spec p.59.
	GetOptionChain(context.Context, *GetOptionChainRequest) (*GetOptionChainResponse, error)
	GetListingDailyHistory(context.Context, *GetListingDailyHistoryRequest) (*GetListingDailyHistoryResponse, error)
	CreateOrder(context.Context, *CreateOrderRequest) (*CreateOrderResponse, error)
	ListOrders(context.Context, *ListOrdersRequest) (*ListOrdersResponse, error)
	GetOrder(context.Context, *GetOrderRequest) (*Order, error)
	ApproveOrder(context.Context, *ApproveOrderRequest) (*Order, error)
	DeclineOrder(context.Context, *DeclineOrderRequest) (*Order, error)
	CancelOrder(context.Context, *CancelOrderRequest) (*Order, error)
	ListHoldings(context.Context, *ListHoldingsRequest) (*ListHoldingsResponse, error)
	SetPublicCount(context.Context, *SetPublicCountRequest) (*Holding, error)
	// ExerciseOption is spec p.61.d — actuaries may exercise an in-the-
	// money option before settlementDate. Result tells the FE the
	// remaining option position + the underlying-side effect.
	ExerciseOption(context.Context, *ExerciseOptionRequest) (*ExerciseOptionResponse, error)
	ListTaxPositions(context.Context, *ListTaxPositionsRequest) (*ListTaxPositionsResponse, error)
	RunTax(context.Context, *RunTaxRequest) (*RunTaxResponse, error)
	ListRealizedPnL(context.Context, *ListRealizedPnLRequest) (*ListRealizedPnLResponse, error)
	// ListPublicHoldings drives the OTC discovery board (spec p.67):
	// holdings owned by other users that have public_count > reserved_count
	// are visible. Filterable by ticker.
	ListPublicHoldings(context.Context, *ListPublicHoldingsRequest) (*ListPublicHoldingsResponse, error)
	// CreateOTCOffer opens a new negotiation thread. The buyer initiates;
	// the seller_holding_id resolves the seller (its owner). Increments
	// reserved_count on the seller's holding by quantity.
	CreateOTCOffer(context.Context, *CreateOTCOfferRequest) (*OTCOffer, error)
	// CounterOfferOTC appends a new iteration to an existing thread. The
	// prior open row flips to `superseded`; reservation is adjusted if
	// quantity changed. modified_by tracks which party last touched the
	// thread (drives the FE unread badge).
	CounterOfferOTC(context.Context, *CounterOfferOTCRequest) (*OTCOffer, error)
	// WithdrawOTCOffer pulls a thread out of negotiation. Either party
	// may call; the open row flips to `withdrawn` and the seller's
	// reservation is released.
	WithdrawOTCOffer(context.Context, *WithdrawOTCOfferRequest) (*OTCOffer, error)
	// ListOTCThreads drives the "Aktivne ponude" page (spec p.69) — every
	// thread the caller participates in (as buyer or seller), most-recent
	// iteration per thread.
	ListOTCThreads(context.Context, *ListOTCThreadsRequest) (*ListOTCThreadsResponse, error)
	// GetOTCThread returns every iteration in a thread (oldest first).
	// Drives the thread-detail modal on spec p.69.
	GetOTCThread(context.Context, *GetOTCThreadRequest) (*GetOTCThreadResponse, error)
	// AcceptOTCOffer accepts the open iteration in a thread and mints
	// an active contract via the otc_premium SAGA (premium transfers
	// from buyer to seller; contract row is created; seller's holding
	// reservation rolls over from offer to contract).
	AcceptOTCOffer(context.Context, *AcceptOTCOfferRequest) (*AcceptOTCOfferResponse, error)
	// ListOTCContracts drives the "Sklopljeni ugovori" page (spec p.69)
	// for the caller. Supervisors/admin may filter by user_id.
	ListOTCContracts(context.Context, *ListOTCContractsRequest) (*ListOTCContractsResponse, error)
	// GetOTCContract returns one contract (caller must be a party or
	// supervisor/admin).
	GetOTCContract(context.Context, *GetOTCContractRequest) (*OTCContract, error)
	// ExerciseOTCContract runs the otc_exercise SAGA on an active
	// contract (spec p.80 intra-bank): buyer pays qty * strike to seller,
	// shares transfer, contract flips to `exercised`. Buyer's cost basis
	// on the received shares is `strike_price`; seller writes a
	// realized_gains row.
	ExerciseOTCContract(context.Context, *ExerciseOTCContractRequest) (*ExerciseOTCContractResponse, error)
	// ListFunds returns the fund discovery list (spec p.71). Supervisors
	// and clients with funds.read.* can browse; rows include total_value,
	// profit, and minimum_contribution for sorting/filtering.
	ListFunds(context.Context, *ListFundsRequest) (*ListFundsResponse, error)
	// GetFund returns the fund detail including its holdings list and the
	// caller's position when one exists. Spec p.74.
	GetFund(context.Context, *GetFundRequest) (*GetFundResponse, error)
	// CreateFund mints a new fund (supervisor only — spec p.74). Bank
	// service is called internally to open the fund's RSD account; the
	// creator becomes the default manager.
	CreateFund(context.Context, *CreateFundRequest) (*Fund, error)
	// InvestInFund runs the fund_invest SAGA: reserves the source
	// account, transfers to the fund's bank account (FX hop if needed),
	// upserts the client_fund_positions row (units math) and writes a
	// client_fund_transactions row. Verification-gated (FOUND-9).
	InvestInFund(context.Context, *InvestInFundRequest) (*FundTransactionResponse, error)
	// WithdrawFromFund runs the fund_withdraw SAGA. Liquid path (fund
	// has enough RSD on its bank account) reserves and transfers
	// directly; illiquid path stays in `pending` while auto-liquidation
	// orders settle the gap. Verification-gated.
	WithdrawFromFund(context.Context, *WithdrawFromFundRequest) (*FundTransactionResponse, error)
	// ListFundPositions returns the caller's positions across all funds
	// (clients) or a specified user's (supervisors/admin). Supervisors
	// may pass the BankAsClient sentinel UUID to see the bank's stakes
	// (FE-FUND-6, Profit Banke "Bank fund positions").
	ListFundPositions(context.Context, *ListFundPositionsRequest) (*ListFundPositionsResponse, error)
	// GetFundPerformance returns the daily liquid_rsd + holdings_value_rsd
	// time series for a fund. FE-FUND-2 chart.
	GetFundPerformance(context.Context, *GetFundPerformanceRequest) (*GetFundPerformanceResponse, error)
	// ListFundTransactions returns the audit log of invest/withdraw rows
	// for a fund. Supervisors see everything; clients see only their own.
	ListFundTransactions(context.Context, *ListFundTransactionsRequest) (*ListFundTransactionsResponse, error)
	ListActuaryPerformances(context.Context, *ListActuaryPerformancesRequest) (*ListActuaryPerformancesResponse, error)
	ListBankFundPositions(context.Context, *ListBankFundPositionsRequest) (*ListBankFundPositionsResponse, error)
	// ReassignSupervisorAssets reassigns every fund managed by `from_user_id`
	// to `to_user_id`. Internal-only (no http annotation) — called by
	// user-svc inside SetEmployeePermissions when the funds.manage.supervisor
	// permission is being revoked, so the demoted supervisor can't orphan
	// their managed funds. Idempotent: a fund already managed by
	// `to_user_id` is a no-op.
	ReassignSupervisorAssets(context.Context, *ReassignSupervisorAssetsRequest) (*ReassignSupervisorAssetsResponse, error)
}

